#include<bits/stdc++.h>
using namespace std;
int n,m;
vector<int> mp[4096];
long long dp[12][4096];
bool flag[4096];
bool check(int x)
{
    int cnt=0;
    for(int i=0;i<n;i++)
    {
        if(x&(1<<i))
        {
            if(cnt%2==1)
            {
                return false; 
            }
            cnt=0;
        }
        else
        {
            cnt++;
        }
    }
    return cnt%2==0;
}
int main()
{
    while(scanf("%d%d",&n,&m)==2&&n)
    {
        for(int i=0;i<(1<<n);i++)
        {
            flag[i]=check(i);
        }
        for(int i=0;i<(1<<n);i++)
        {
            mp[i].clear();
            for(int j=0;j<(1<<n);j++)
            {
                if(!(i&j)&&flag[i|j])
                {
                    mp[i].push_back(j);
                }
            }
        }
        memset(dp,0,sizeof(dp));
        dp[0][0]=1;
        for(int i=1;i<=m;i++)
        {
            for(int j=0;j<(1<<n);j++)
            {
                for(int k:mp[j])
                {
                    dp[i][j]+=dp[i-1][k];
                }
            }
        }
        printf("%lld\n",dp[m][0]);
    }
    return 0;
}
